--- 筛选列表
local FilterType = {
    --- 全部
    All = 1,
    --- 单人
    Single = 2,
    --- 集结
    Converge = 3,
    --- 胜利
    Win = 4,
    --- 失败
    Lose = 5,
    --- 关注
    Focus = 6,
    --- 高兵损
    Loss = 7,

}

local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxMailCtrl:LxBaseCtrl
local LxMailCtrl = classX("LxMailCtrl", LxBaseCtrl)

function LxMailCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
    self._panelStack = {}
    --- 缓存解析后的战报信息数据
    self._mailReportList = {}
end

function LxMailCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

function LxMailCtrl:FormatContent(str)
    local t = {}
    local needReplace = true
    for k in string.gmatch(str, "#(%w+)#") do
        local typeStr = string.sub(k, 1,1)
        local valIdx = tonumber(string.sub(k, 2))
        if typeStr == "c" then
            if valIdx == 1 then
                t[k] = LxAppHelper.GetAppName()
                needReplace = true
            end
        end
    end
    if needReplace then
        return string.gsub(str, "#(%w+)#", t)
    else
        return str
    end
end

function LxMailCtrl:OnMailReceive(receiveType, mailIds, thingsInfo)
    ModuleCenter.Mail:SetMailReceive(mailIds)
    if thingsInfo then
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Mail, thingsInfo)
    end
    FireEvent(EventNames.MAIL_RECEIVE, mailIds, receiveType)
end

function LxMailCtrl:OnMailRemove(removeType, mailIds, thingsInfo)
    ModuleCenter.Mail:SetMailRemove(mailIds)
    ShowSysMsg(I18nText(5665))
    if thingsInfo then
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Mail, thingsInfo)
    end
    FireEvent(EventNames.MAIL_REMOVE, mailIds, removeType)
end

function LxMailCtrl:OnMailRead(mailId)
    ModuleCenter.Mail:SetMailRead(mailId)
    FireEvent(EventNames.MAIL_READ, mailId)
end

--- 筛选页签
function LxMailCtrl:GetFilterList()
    local showList = {}
    for i, v in pairs(FilterType) do
        local _t = {}
        _t.type = v
        _t.sort = v
        _t.name = I18nText(5603 + v)
        table.insert(showList, _t)
    end
    table.sort(showList, function(a, b) return a.sort < b.sort end)
    return showList
end

--- @param type number 邮件展示类型
--- @param filter number 筛选类型
function LxMailCtrl:GetMailList(type, filter)
    if type == MailShowType.Collect then
        return self:GetCollectList()
    end
    local showList = {}
    local mailList = ModuleCenter.Mail:GetMailListByShowType(type)
    if filter == FilterType.All then
        if type == MailShowType.Report then
            return self:ArrangeMailList(mailList)
        else
            return mailList
        end
    end
    for i, v in ipairs(mailList) do
        if (filter == FilterType.Single and not v.isMass) or    -- 单人
                (filter == FilterType.Converge and v.isMass) or  -- 集结
                (filter == FilterType.Win and v.isWin) or        -- 胜利
                (filter == FilterType.Lose and not v.isWin) or   -- 失败
                (filter == FilterType.Focus and v.followed) or   -- 关注
                (filter == FilterType.Loss and v.highLose) then   -- 高兵损
            table.insert(showList, v)
        end
    end
    return showList
end
--- @param strType number 类型 1 标题 2 内容 3 署名 4 邮件外标题
function LxMailCtrl:GetMailStr(mailObj, strType)
    local showStr
    if strType == 1 then
        showStr = mailObj.showTitle
    elseif strType == 2 then
        showStr = mailObj.showContent
    elseif strType == 3 then
        showStr = mailObj.showSignature
    else
        showStr = mailObj.showAbbreviateText
    end
    if string.isempty(showStr)  then
        local mailType = mailObj.mailType
        local isNeedFilter = true
        if mailType == MailType.Normal or mailType == MailType.Report then
            local refId = mailObj.refId
            local ref = GameTable.GameMailRef[refId]
            if not ref then
                if LOG_INFO_ENABLED then
                    printError("mail", "邮件refId=%d不存在", mailObj.refId)
                end
                showStr = ""
            else
                if strType ~= 3 then
                    local decodeStr = ""
                    local repStr = ""
                    if strType == 1 then
                        decodeStr = mailObj.tile
                        repStr = ref.title
                    elseif strType == 2 then
                        decodeStr = mailObj.content
                        repStr = ref.text
                    else
                        decodeStr = mailObj.content
                        repStr = ref.abbreviateText
                    end
                    local params = CJSON.decode(decodeStr)
                    local _t = {}
                    if params then
                        for i, v in pairs(params) do
                            local _str = I18nTextFromTable(v)
                            if string.isempty(_str) then
                                _t[i] = v
                            else
                                _t[i] = _str
                            end
                        end
                    end
                    showStr = I18nText(repStr, _t)
                else
                    showStr = I18nText(ref.signature)
                end
            end
            isNeedFilter = self:IsNeedFilter(refId)
        elseif mailType == 2 then
            if strType == 1 then
                showStr = mailObj.tile
            elseif strType == 2 or strType == 4 then
                showStr = mailObj.content
            else
                showStr = mailObj.signature
            end
        else
            showStr = ""
        end
        if not string.isempty(showStr) then
            showStr = self:FormatContent(showStr)
        end
        if not string.isempty(showStr) and isNeedFilter then
            local _r, newContent, _o = MgrCenter.MaskWordMgr:FilterWord(showStr, nil, true, 3)
            showStr = newContent
        end
        if strType == 1 then
            mailObj.showTitle = showStr
        elseif strType == 2 then
            mailObj.showContent = showStr
        elseif strType == 3 then
            mailObj.showSignature = showStr
        else
            mailObj.showAbbreviateText = showStr
        end
    end
    return showStr
end

function LxMailCtrl:IsNeedFilter(refId)
    if not self._filterMap then
        local dataMap = {}
        local list = GameTable.GameMailConfigRef.mailFilter or {}
        for k,v in ipairs(list) do
            dataMap[v] = true
        end
        self._filterMap = dataMap
    end
    return self._filterMap[refId]
end
