--- 根据战报属性字段 获取邮件的展示属性列表
function LxMailCtrl:GetAttrShowList(attrInfo)
    local showList = {}
    local initAttrList = self:GetInitShowAttrList()
    for _, v in ipairs(attrInfo.attrTypes) do
        --- 所有同类型属性合并到一起
        local _attrList = initAttrList[v.soldierType]
        for _, v2 in ipairs(v.attrs) do
            if _attrList[v2.refId] then
                _attrList[v2.refId].value = _attrList[v2.refId].value + v2.value
                _attrList[v2.refId].source = v2.source -- 属性来源，约定值，见：AttrSourceEnum
                _attrList[v2.refId].totalRate = v.totalRate    --- 总倍率
            end
        end
    end
    for i, v in pairs(initAttrList) do
        for _, v2 in pairs(v) do
            table.insert(showList, v2)
        end
    end
    table.sort(showList, function(a, b)
        return a.sort < b.sort
    end)
    return showList
end
--- 获取属性 属性按类型分组信息
--- @param subType number 士兵类型
--- @param attrType number 属性类型
function LxMailCtrl:GetAttrInfoList(attrInfo, subType, attrType)
    local showList = {}
    local totalRate = 0 --- 总倍率
    for _, v in ipairs(attrInfo.attrTypes) do
        if not subType or v.soldierType == subType then
            totalRate = v.totalRate
            for _, v2 in ipairs(v.attrs) do
                if attrType == v2.refId then
                    table.insert(showList, v2)
                end
            end
        end
    end
    return showList, totalRate
end

