--- 获取对应的属性来源名字
function LxMailCtrl:GetAttrSource(source)
    local sourceList = GameTable.MailSourceRef
    for i, v in pairs(sourceList) do
        for _, v2 in ipairs(v.sourceId) do
            if v2 == source then
                return I18nText(v.name)
            end
        end
    end
    return ""
end
--- 固定显示 3个兵种 4种属性
function LxMailCtrl:GetInitShowAttrList()
    local initAttr = {31, 32, 33, 35}   -- 固定显示的属性
    local showList = {}
    local refList = GameTable.SoldierTypeRef
    local attrRefList = GameTable.CombatAttributeRef
    for i, v in ipairs(refList) do
        local _t = {}
        for _, v2 in ipairs(initAttr) do
            local _attr = {}
            local ref = attrRefList[v2]
            _attr.type = v.refId
            _attr.attrId = v2
            _attr.value = 0
            _attr.source = 0
            _attr.totalRate = 0
            _attr.sort = v.refId * 10000 + ref.sort
            _t[v2] = _attr
        end
        showList[v.refId] = _t
    end
    return showList
end

--- 报告类的邮件 要把 采集类的所有邮件 外部列表 只保留一封最新的
function LxMailCtrl:ArrangeMailList(mailList)
    local showList = {}
    local gather = 0
    local mailRefList = GameTable.GameMailRef
    for i, v in ipairs(mailList) do
        local ref = mailRefList[v.refId]
        if ref then
            if ref.contentType == MailContentType.Gather then
                if gather == 0 then
                    table.insert(showList, v)
                    gather = 1
                end
            else
                table.insert(showList, v)
            end
        else
            table.insert(showList, v)
        end
    end
    return showList
end

function LxMailCtrl:CloseMailCtrl()
    local uiNames = self:GetAllUiName()
    for i = #uiNames, 1, -1 do
        local uiName = table.remove(uiNames, i)
        if IsOpenPanel(uiName) then
            ClosePanel(uiName)
        end
    end
    if IsOpenPanel(UiNames.Mail) then
        ClosePanel(UiNames.Mail)
    end
    if IsOpenPanel(UiNames.MailShare) then
        ClosePanel(UiNames.MailShare)
    end
end
--- 获取所有的采集邮件类别
function LxMailCtrl:GetAllGatherMailList()
    local showList = {}
    local mailRefList = GameTable.GameMailRef

    local dataList = ModuleCenter.Mail:GetMailListByShowType(MailShowType.Report)
    for i, v in ipairs(dataList) do
        local ref = mailRefList[v.refId]
        if ref.contentType == MailContentType.Gather then
            table.insert(showList, v)
        end
    end
    return showList
end
--- 获取出征的英雄的种族加成
function LxMailCtrl:GetHeroRaceRef(heroList)
    if not heroList or #heroList < 3 then
        return nil
    end

    local raceType = -1
    ---@type V_HeroRef
    local heroRef = nil
    local heroRefList = GameTable.CharacterRef
    for _, v in ipairs(heroList) do
        heroRef = heroRefList[v.refId]
        if heroRef and (raceType < 0 or heroRef.raceType == raceType) then
            raceType = heroRef.raceType
        else
            raceType = -1
            break
        end
    end
    ---@type V_HeroRaceRef
    local raceRef = GameTable.CharacterRaceRef[raceType]
    return raceRef
end

