--- 获取英雄经营技能 跟 slg技能 列表
function LxMailCtrl:GetHeroMailSkillList(refId, star, heroObj)
    local starId = LxDataHelper.GetHeroStarId(refId, star)
    local starRef = LxDataHelper.GetHeroStarRef(starId)
    local showSkillList = {}
    if starRef.skillBuild then
        for i, v in ipairs(starRef.skillBuild) do
            table.insert(showSkillList, { skillData = v , heroObj = heroObj})
        end
    end
    if starRef.skillArmy then
        for i, v in ipairs(starRef.skillArmy) do
            table.insert(showSkillList, { skillData = v , heroObj = heroObj})
        end
    end
    return showSkillList
end
